 using System.ComponentModel;
 using System.Net.Http.Json;
 using System.Text.Json;
 using Microsoft.Agents.AI;
 using Microsoft.Extensions.AI;

 var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
     ?? throw new InvalidOperationException(
         "Set the OPENAI_API_KEY environment variable before running this app.");

 var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

 // --- Build the chat client through the MEAI abstraction ---
 IChatClient chatClient = new OpenAI.OpenAIClient(apiKey)
     .GetChatClient(modelId)
     .AsIChatClient();

 // --- Define tools the agent can use ---
 var tools = new List<AITool>
 {
     AIFunctionFactory.Create(WebSearchTool.SearchAsync, nameof(WebSearchTool.SearchAsync),
         "Search the web for information on a given query. Returns a list of result snippets."),
     AIFunctionFactory.Create(NotesTool.AddNote, nameof(NotesTool.AddNote),
         "Save a research note with a title and body for later reference."),
     AIFunctionFactory.Create(NotesTool.GetNotes, nameof(NotesTool.GetNotes),
         "Retrieve all saved research notes collected so far."),
 };

 // --- Create the agent with instructions ---
 const string instructions = """
     You are a research assistant. When given a topic:
     1. Search the web multiple times with varied queries to gather diverse information.
     2. As you find useful information, save key findings as notes using the note-taking tool.
     3. After gathering enough information (at least 3 searches), retrieve your notes
        and produce a well-structured summary with the following sections:
        - **Overview**: A brief introduction to the topic.
        - **Key Findings**: Bullet points of the most important facts.
        - **Sources**: List the sources you found.
     Always cite where information came from. Be thorough but concise.
     """;

 var agent = new ChatClientAgent(
     chatClient,
     instructions: instructions,
     name: "ResearchAgent",
     description: "An agent that researches topics using web search and note-taking.",
     tools: tools);

