 static string PromptForTopic()
 {
     Console.Write("Enter a research topic: ");
     var topic = Console.ReadLine()?.Trim();
     if (string.IsNullOrWhiteSpace(topic))
     {
         Console.WriteLine("No topic provided. Using default topic.");
         topic = "recent advances in quantum computing";
     }
     return topic;
 }

 // ────────────────────────────────────────────────────────────────
 // Tool: Web Search (uses DuckDuckGo Instant Answer API — no key)
 // ────────────────────────────────────────────────────────────────

 static class WebSearchTool
 {
     private static readonly HttpClient s_http = new()
     {
         DefaultRequestHeaders =
         {
             { "User-Agent", "ResearchAgent/1.0" },
         },
         Timeout = TimeSpan.FromSeconds(15),
     };

     [Description("Search the web for information. Returns result snippets.")]
     public static async Task<string> SearchAsync(
         [Description("The search query to look up on the web.")] string query)
     {
         Console.WriteLine($"  🌐 Searching: \"{query}\"");
         try
         {
             var url = $"https://api.duckduckgo.com/?q={Uri.EscapeDataString(query)}&format=json&no_html=1&skip_disambig=1";
             using var response = await s_http.GetAsync(url);
             response.EnsureSuccessStatusCode();

             var json = await response.Content.ReadFromJsonAsync<JsonElement>();
             var results = new List<string>();

             // Abstract
             var abstractText = json.GetProperty("AbstractText").GetString();
             var abstractSource = json.GetProperty("AbstractSource").GetString();
             if (!string.IsNullOrWhiteSpace(abstractText))
             {
                 results.Add($"[{abstractSource}] {abstractText}");
             }

             // Related topics
             if (json.TryGetProperty("RelatedTopics", out var relatedTopics))
             {
                 foreach (var topic in relatedTopics.EnumerateArray().Take(5))
                 {
                     if (topic.TryGetProperty("Text", out var text))
                     {
                         var snippet = text.GetString();
                         if (!string.IsNullOrWhiteSpace(snippet))
                         {
                             var topicUrl = topic.TryGetProperty("FirstURL", out var u) ? u.GetString() : "";
                             results.Add($"[{topicUrl}] {snippet}");
                         }
                     }
                 }
             }

             // Answer
             var answer = json.GetProperty("Answer").GetString();
             if (!string.IsNullOrWhiteSpace(answer))
             {
                 results.Add($"[Answer] {answer}");
             }

             if (results.Count == 0)
             {
                 return $"No detailed results found for \"{query}\". Try rephrasing the query.";
             }

             return string.Join("\n\n", results);
         }
         catch (Exception ex)
         {
             return $"Search failed for \"{query}\": {ex.Message}. Try a different query.";
         }
     }
 }

 // ────────────────────────────────────────────────────────────────
 // Tool: Note-Taking
 // ────────────────────────────────────────────────────────────────

 static class NotesTool
 {
     private static readonly List<(string Title, string Body)> s_notes = [];

     public static int NoteCount => s_notes.Count;

     [Description("Save a research note for later reference.")]
     public static string AddNote(
         [Description("Short title for the note.")] string title,
         [Description("Detailed content of the note.")] string body)
     {
         s_notes.Add((title, body));
         Console.WriteLine($"  📝 Note saved: \"{title}\"");
         return $"Note #{s_notes.Count} saved: \"{title}\".";
     }

     [Description("Retrieve all saved research notes.")]
     public static string GetNotes()
     {
         if (s_notes.Count == 0)
         {
             return "No notes have been saved yet.";
         }

         return string.Join("\n\n", s_notes.Select((n, i) =>
             $"--- Note #{i + 1}: {n.Title} ---\n{n.Body}"));
     }
 }

